#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        int max1 = (a > b) ? a : b;
        int max2 = (b > c) ? b : c;
        int max3 = (a > c) ? a : c;
        int result = (max1 > max2) ? max1 : max2;
        result = (result > max3) ? result : max3;
        printf("%d\n", result);
    }
    return 0;
}

