const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
        i++;
    } else {
        let [a, b, c] = line.split(' ').map(num => parseInt(num));
        let max1 = Math.max(a, b);
        let max2 = Math.max(b, c);
        let max3 = Math.max(a, c);
        let result = Math.max(max1, max2);
        result = Math.max(result, max3);
        console.log(result);
        i++;
        if (i > T) {
            readline.close();
        }
    }
});
